+/**
+ * Integration tests for the full analytics pipeline.
+ *
+ * Tests the complete flow: AnalyticsRouteHandler → AnalyticsService → AnalyticsRepository → Database.
+ * Unlike unit tests, these exercise the entire stack with realistic data scenarios.
+ */
+
+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { AnalyticsRepository } from '../../src/repositories/analytics.repository.js';
+import { AnalyticsService } from '../../src/services/analytics.service.js';
+import { AnalyticsRouteHandler } from '../../src/routes/analytics.routes.js';
+import type { OrderStatus } from '../../src/models/order.js';
+
+describe('Analytics Pipeline Integration', () => {
+  let db: Database;
+  let handler: AnalyticsRouteHandler;
+
+  beforeEach(() => {
+    db = new Database();
+    const repo = new AnalyticsRepository(db);
+    const service = new AnalyticsService(repo);
+    handler = new AnalyticsRouteHandler(service);
+  });
+
+  // ── Test data helpers ───────────────────────────────────────────
+
+  function insertOrder(opts: {
+    id: string;
+    total: number;
+    status?: OrderStatus;
+    createdAt?: string;
+    items?: Array<{ productId: string; name: string; quantity: number; unitPrice: number }>;
+  }) {
+    db.insert('orders', {
+      id: opts.id,
+      userId: 'user-1',
+      items: opts.items ?? [{ productId: 'prod-default', name: 'Default Widget', quantity: 1, unitPrice: opts.total }],
+      total: opts.total,
+      status: opts.status ?? 'confirmed',
+      createdAt: opts.createdAt ?? new Date('2026-01-15').toISOString(),
+      updatedAt: opts.createdAt ?? new Date('2026-01-15').toISOString(),
+    });
+  }
+
+  function insertUser(id: string, createdAt: string) {
+    db.insert('users', {
+      id,
+      name: `User ${id}`,
+      email: `${id}@example.com`,
+      role: 'member',
+      createdAt: new Date(createdAt).toISOString(),
+      updatedAt: new Date(createdAt).toISOString(),
+    });
+  }
+
+  // ── Full dashboard pipeline ─────────────────────────────────────
+
+  describe('dashboard end-to-end', () => {
+    it('should return complete dashboard with all data populated', () => {
+      // Seed realistic data across January 2026
+      insertOrder({ id: 'o1', total: 100, status: 'confirmed', createdAt: '2026-01-05' });
+      insertOrder({ id: 'o2', total: 250, status: 'shipped', createdAt: '2026-01-10' });
+      insertOrder({ id: 'o3', total: 75, status: 'pending', createdAt: '2026-01-20' });
+      insertOrder({ id: 'o4', total: 300, status: 'delivered', createdAt: '2026-01-25' });
+      insertOrder({ id: 'o5', total: 50, status: 'cancelled', createdAt: '2026-01-28' });
+      insertUser('u1', '2026-01-03');
+      insertUser('u2', '2026-01-15');
+      insertUser('u3', '2026-01-22');
+
+      const result = handler.handleGetDashboard({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        granularity: 'day',
+      });
+
+      expect(result.success).toBe(true);
+      const data = result.data!;
+
+      // Metrics
+      expect(data.metrics).toHaveLength(4);
+      const revenue = data.metrics.find(m => m.type === 'revenue')!;
+      expect(revenue.currentValue).toBe(775);
+      const orders = data.metrics.find(m => m.type === 'orders')!;
+      expect(orders.currentValue).toBe(5);
+      const users = data.metrics.find(m => m.type === 'users')!;
+      expect(users.currentValue).toBe(3);
+      const aov = data.metrics.find(m => m.type === 'average-order-value')!;
+      expect(aov.currentValue).toBe(155);
+
+      // Status breakdown
+      expect(data.ordersByStatus).toHaveLength(5);
+      expect(data.ordersByStatus.find(s => s.status === 'confirmed')!.count).toBe(1);
+      expect(data.ordersByStatus.find(s => s.status === 'shipped')!.count).toBe(1);
+      expect(data.ordersByStatus.find(s => s.status === 'pending')!.count).toBe(1);
+      expect(data.ordersByStatus.find(s => s.status === 'delivered')!.count).toBe(1);
+      expect(data.ordersByStatus.find(s => s.status === 'cancelled')!.count).toBe(1);
+
+      // Time series
+      expect(data.revenueOverTime.points.length).toBeGreaterThan(0);
+      const totalTimeSeriesRevenue = data.revenueOverTime.points.reduce((s, p) => s + p.value, 0);
+      expect(totalTimeSeriesRevenue).toBe(775);
+
+      expect(data.newUsersOverTime.points.length).toBeGreaterThan(0);
+      const totalNewUsers = data.newUsersOverTime.points.reduce((s, p) => s + p.value, 0);
+      expect(totalNewUsers).toBe(3);
+    });
+
+    it('should handle empty database gracefully', () => {
+      const result = handler.handleGetDashboard({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        granularity: 'day',
+      });
+
+      expect(result.success).toBe(true);
+      const data = result.data!;
+      expect(data.metrics.every(m => m.currentValue === 0)).toBe(true);
+      expect(data.ordersByStatus.every(s => s.count === 0)).toBe(true);
+      expect(data.revenueOverTime.points).toHaveLength(0);
+    });
+
+    it('should correctly filter data by time range across the full pipeline', () => {
+      insertOrder({ id: 'o-before', total: 999, createdAt: '2025-12-31' });
+      insertOrder({ id: 'o-in-1', total: 100, createdAt: '2026-01-15' });
+      insertOrder({ id: 'o-in-2', total: 200, createdAt: '2026-01-20' });
+      insertOrder({ id: 'o-after', total: 888, createdAt: '2026-02-01' });
+      insertUser('u-before', '2025-12-31');
+      insertUser('u-in', '2026-01-10');
+      insertUser('u-after', '2026-02-01');
+
+      const result = handler.handleGetDashboard({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+      });
+
+      expect(result.success).toBe(true);
+      const data = result.data!;
+      const revenue = data.metrics.find(m => m.type === 'revenue')!;
+      expect(revenue.currentValue).toBe(300);
+      const userMetric = data.metrics.find(m => m.type === 'users')!;
+      expect(userMetric.currentValue).toBe(1);
+    });
+  });
+
+  // ── Metric queries end-to-end ──────────────────────────────────
+
+  describe('metric queries end-to-end', () => {
+    it('should compute period-over-period comparison through the route handler', () => {
+      // Previous period: Dec 2025 — two orders totaling 200
+      insertOrder({ id: 'o-prev-1', total: 100, createdAt: '2025-12-10' });
+      insertOrder({ id: 'o-prev-2', total: 100, createdAt: '2025-12-20' });
+      // Current period: Jan 2026 — three orders totaling 450
+      insertOrder({ id: 'o-curr-1', total: 150, createdAt: '2026-01-05' });
+      insertOrder({ id: 'o-curr-2', total: 200, createdAt: '2026-01-15' });
+      insertOrder({ id: 'o-curr-3', total: 100, createdAt: '2026-01-25' });
+
+      const result = handler.handleGetMetric({
+        type: 'revenue',
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        granularity: 'day',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data!.currentValue).toBe(450);
+      expect(result.data!.previousValue).toBe(200);
+      expect(result.data!.changePercent).toBe(125);
+    });
+
+    it('should return all four metric types with consistent data', () => {
+      insertOrder({ id: 'o1', total: 100, createdAt: '2026-01-15' });
+      insertOrder({ id: 'o2', total: 200, createdAt: '2026-01-20' });
+      insertUser('u1', '2026-01-10');
+
+      const types = ['revenue', 'orders', 'users', 'average-order-value'] as const;
+      const expected = { revenue: 300, orders: 2, users: 1, 'average-order-value': 150 };
+
+      for (const type of types) {
+        const result = handler.handleGetMetric({
+          type,
+          startDate: '2026-01-01',
+          endDate: '2026-01-31',
+          granularity: 'day',
+        });
+        expect(result.success).toBe(true);
+        expect(result.data!.currentValue).toBe(expected[type]);
+      }
+    });
+
+    it('should include time series points in metric response', () => {
+      insertOrder({ id: 'o1', total: 100, createdAt: '2026-01-05' });
+      insertOrder({ id: 'o2', total: 200, createdAt: '2026-01-20' });
+
+      const result = handler.handleGetMetric({
+        type: 'revenue',
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        granularity: 'day',
+      });
+
+      expect(result.success).toBe(true);
+      const points = result.data!.timeSeries.points;
+      expect(points.length).toBeGreaterThan(0);
+      const totalFromTimeSeries = points.reduce((s, p) => s + p.value, 0);
+      expect(totalFromTimeSeries).toBe(300);
+    });
+
+    it('should handle zero previous period gracefully', () => {
+      insertOrder({ id: 'o1', total: 500, createdAt: '2026-01-15' });
+
+      const result = handler.handleGetMetric({
+        type: 'revenue',
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        granularity: 'day',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data!.previousValue).toBe(0);
+      expect(result.data!.changePercent).toBe(0);
+    });
+  });
+
+  // ── Time-range filtering ───────────────────────────────────────
+
+  describe('time-range filtering', () => {
+    it('should include orders at exact boundary dates', () => {
+      insertOrder({ id: 'o-start', total: 100, createdAt: '2026-01-01' });
+      insertOrder({ id: 'o-end', total: 200, createdAt: '2026-01-31' });
+
+      const result = handler.handleGetMetric({
+        type: 'revenue',
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        granularity: 'day',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data!.currentValue).toBe(300);
+    });
+
+    it('should work with different granularities', () => {
+      insertOrder({ id: 'o1', total: 100, createdAt: '2026-01-05' });
+      insertOrder({ id: 'o2', total: 200, createdAt: '2026-01-20' });
+
+      for (const granularity of ['hour', 'day', 'week', 'month']) {
+        const result = handler.handleGetDashboard({
+          startDate: '2026-01-01',
+          endDate: '2026-01-31',
+          granularity,
+        });
+
+        expect(result.success).toBe(true);
+        const revenue = result.data!.metrics.find(m => m.type === 'revenue')!;
+        expect(revenue.currentValue).toBe(300);
+      }
+    });
+
+    it('should handle single-day range', () => {
+      insertOrder({ id: 'o1', total: 42, createdAt: '2026-01-15' });
+
+      const result = handler.handleGetMetric({
+        type: 'revenue',
+        startDate: '2026-01-15',
+        endDate: '2026-01-15',
+        granularity: 'day',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data!.currentValue).toBe(42);
+    });
+
+    it('should filter correctly with ISO datetime strings', () => {
+      insertOrder({ id: 'o1', total: 100, createdAt: '2026-01-15T12:00:00.000Z' });
+
+      const result = handler.handleGetMetric({
+        type: 'revenue',
+        startDate: '2026-01-15T00:00:00.000Z',
+        endDate: '2026-01-15T23:59:59.999Z',
+        granularity: 'hour',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data!.currentValue).toBe(100);
+    });
+  });
+
+  // ── Top products pipeline ──────────────────────────────────────
+
+  describe('top products end-to-end', () => {
+    it('should aggregate products across multiple orders', () => {
+      insertOrder({
+        id: 'o1',
+        total: 150,
+        createdAt: '2026-01-10',
+        items: [
+          { productId: 'p1', name: 'Widget A', quantity: 3, unitPrice: 10 },
+          { productId: 'p2', name: 'Widget B', quantity: 1, unitPrice: 120 },
+        ],
+      });
+      insertOrder({
+        id: 'o2',
+        total: 80,
+        createdAt: '2026-01-20',
+        items: [
+          { productId: 'p1', name: 'Widget A', quantity: 5, unitPrice: 10 },
+          { productId: 'p3', name: 'Widget C', quantity: 2, unitPrice: 15 },
+        ],
+      });
+
+      const result = handler.handleGetTopProducts({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        granularity: 'day',
+      });
+
+      expect(result.success).toBe(true);
+      const products = result.data!;
+      expect(products).toHaveLength(3);
+      // Sorted by revenue: p2 (120), p1 (80), p3 (30)
+      expect(products[0].productId).toBe('p2');
+      expect(products[0].totalRevenue).toBe(120);
+      expect(products[1].productId).toBe('p1');
+      expect(products[1].totalRevenue).toBe(80);
+      expect(products[1].totalQuantity).toBe(8);
+      expect(products[2].productId).toBe('p3');
+      expect(products[2].totalRevenue).toBe(30);
+    });
+
+    it('should respect custom limit through route handler', () => {
+      const items = Array.from({ length: 20 }, (_, i) => ({
+        productId: `p${i}`,
+        name: `Product ${i}`,
+        quantity: 1,
+        unitPrice: (20 - i) * 10,
+      }));
+      insertOrder({ id: 'o1', total: 2100, createdAt: '2026-01-15', items });
+
+      const result = handler.handleGetTopProducts({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        limit: '5',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data!).toHaveLength(5);
+      expect(result.data![0].totalRevenue).toBe(200); // p0: unitPrice=200
+    });
+
+    it('should exclude orders outside the time range', () => {
+      insertOrder({
+        id: 'o-in',
+        total: 50,
+        createdAt: '2026-01-15',
+        items: [{ productId: 'p1', name: 'In-range', quantity: 1, unitPrice: 50 }],
+      });
+      insertOrder({
+        id: 'o-out',
+        total: 999,
+        createdAt: '2026-03-01',
+        items: [{ productId: 'p2', name: 'Out-of-range', quantity: 1, unitPrice: 999 }],
+      });
+
+      const result = handler.handleGetTopProducts({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.data!).toHaveLength(1);
+      expect(result.data![0].productId).toBe('p1');
+    });
+  });
+
+  // ── Error scenarios ────────────────────────────────────────────
+
+  describe('error scenarios', () => {
+    it('should reject missing startDate', () => {
+      const result = handler.handleGetDashboard({ endDate: '2026-01-31' });
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('startDate is required');
+    });
+
+    it('should reject missing endDate', () => {
+      const result = handler.handleGetDashboard({ startDate: '2026-01-01' });
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('endDate is required');
+    });
+
+    it('should reject invalid date format', () => {
+      const result = handler.handleGetDashboard({
+        startDate: 'not-a-date',
+        endDate: '2026-01-31',
+      });
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid startDate');
+    });
+
+    it('should reject startDate after endDate', () => {
+      const result = handler.handleGetDashboard({
+        startDate: '2026-02-01',
+        endDate: '2026-01-01',
+      });
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('startDate must not be after endDate');
+    });
+
+    it('should reject invalid granularity', () => {
+      const result = handler.handleGetDashboard({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        granularity: 'quarter',
+      });
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid granularity');
+    });
+
+    it('should reject missing metric type', () => {
+      const result = handler.handleGetMetric({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+      });
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Metric type is required');
+    });
+
+    it('should reject invalid metric type', () => {
+      const result = handler.handleGetMetric({
+        type: 'profit',
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+      });
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid metric type');
+    });
+
+    it('should reject invalid limit for top products', () => {
+      const result = handler.handleGetTopProducts({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        limit: '-1',
+      });
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid limit');
+    });
+
+    it('should reject limit exceeding maximum', () => {
+      const result = handler.handleGetTopProducts({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        limit: '101',
+      });
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Limit exceeds maximum');
+    });
+
+    it('should reject non-numeric limit', () => {
+      const result = handler.handleGetTopProducts({
+        startDate: '2026-01-01',
+        endDate: '2026-01-31',
+        limit: 'abc',
+      });
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid limit');
+    });
+
+    it('should return error envelope (not throw) for all error types', () => {
+      // Every error path should return {success: false, error: string}, never throw
+      const cases = [
+        () => handler.handleGetDashboard({}),
+        () => handler.handleGetMetric({}),
+        () => handler.handleGetTopProducts({ limit: 'bad' } as any),
+      ];
+
+      for (const fn of cases) {
+        const result = fn();
+        expect(result.success).toBe(false);
+        expect(typeof result.error).toBe('string');
+        expect(result.data).toBeUndefined();
+      }
+    });
+  });
+
+  // ── Data consistency across endpoints ──────────────────────────
+
+  describe('cross-endpoint data consistency', () => {
+    it('should report consistent revenue across dashboard and metric endpoints', () => {
+      insertOrder({ id: 'o1', total: 100, createdAt: '2026-01-10' });
+      insertOrder({ id: 'o2', total: 200, createdAt: '2026-01-20' });
+
+      const params = { startDate: '2026-01-01', endDate: '2026-01-31', granularity: 'day' as const };
+
+      const dashResult = handler.handleGetDashboard(params);
+      const metricResult = handler.handleGetMetric({ type: 'revenue', ...params });
+
+      const dashRevenue = dashResult.data!.metrics.find(m => m.type === 'revenue')!;
+      expect(dashRevenue.currentValue).toBe(metricResult.data!.currentValue);
+      expect(dashRevenue.previousValue).toBe(metricResult.data!.previousValue);
+      expect(dashRevenue.changePercent).toBe(metricResult.data!.changePercent);
+    });
+
+    it('should report consistent order count across dashboard and metric endpoints', () => {
+      insertOrder({ id: 'o1', total: 100, createdAt: '2026-01-10' });
+      insertOrder({ id: 'o2', total: 200, createdAt: '2026-01-20' });
+      insertOrder({ id: 'o3', total: 50, createdAt: '2026-01-25' });
+
+      const params = { startDate: '2026-01-01', endDate: '2026-01-31', granularity: 'day' as const };
+
+      const dashResult = handler.handleGetDashboard(params);
+      const metricResult = handler.handleGetMetric({ type: 'orders', ...params });
+
+      const dashOrders = dashResult.data!.metrics.find(m => m.type === 'orders')!;
+      expect(dashOrders.currentValue).toBe(metricResult.data!.currentValue);
+
+      // Status breakdown total should match order count
+      const statusTotal = dashResult.data!.ordersByStatus.reduce((s, b) => s + b.count, 0);
+      expect(statusTotal).toBe(3);
+    });
+
+    it('should report consistent top products revenue with total revenue metric', () => {
+      insertOrder({
+        id: 'o1',
+        total: 150,
+        createdAt: '2026-01-10',
+        items: [
+          { productId: 'p1', name: 'A', quantity: 3, unitPrice: 10 },
+          { productId: 'p2', name: 'B', quantity: 1, unitPrice: 120 },
+        ],
+      });
+
+      const params = { startDate: '2026-01-01', endDate: '2026-01-31', granularity: 'day' as const };
+
+      const topResult = handler.handleGetTopProducts(params);
+      const topRevenue = topResult.data!.reduce((s, p) => s + p.totalRevenue, 0);
+
+      // Top products revenue comes from item-level (quantity * unitPrice),
+      // so it equals 30 + 120 = 150, matching order total
+      expect(topRevenue).toBe(150);
+    });
+  });
+
+  // ── Realistic multi-month scenario ─────────────────────────────
+
+  describe('realistic multi-month scenario', () => {
+    it('should handle a quarter of data with monthly granularity', () => {
+      // Seed Q1 2026 data
+      const months = ['2026-01', '2026-02', '2026-03'];
+      months.forEach((month, mi) => {
+        for (let i = 0; i < 10; i++) {
+          const day = String(i + 1).padStart(2, '0');
+          insertOrder({
+            id: `o-${month}-${i}`,
+            total: (mi + 1) * 50,
+            status: ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'][i % 5] as OrderStatus,
+            createdAt: `${month}-${day}`,
+            items: [
+              { productId: `p${i % 3}`, name: `Product ${i % 3}`, quantity: i + 1, unitPrice: 10 },
+            ],
+          });
+        }
+        for (let i = 0; i < 5; i++) {
+          insertUser(`u-${month}-${i}`, `${month}-${String(i + 1).padStart(2, '0')}`);
+        }
+      });
+
+      const result = handler.handleGetDashboard({
+        startDate: '2026-01-01',
+        endDate: '2026-03-31',
+        granularity: 'month',
+      });
+
+      expect(result.success).toBe(true);
+      const data = result.data!;
+
+      // Revenue: 10*50 + 10*100 + 10*150 = 500 + 1000 + 1500 = 3000
+      const revenue = data.metrics.find(m => m.type === 'revenue')!;
+      expect(revenue.currentValue).toBe(3000);
+
+      const orderCount = data.metrics.find(m => m.type === 'orders')!;
+      expect(orderCount.currentValue).toBe(30);
+
+      const userCount = data.metrics.find(m => m.type === 'users')!;
+      expect(userCount.currentValue).toBe(15);
+
+      // Each status appears 2 times per month * 3 months = 6
+      const statusCounts = data.ordersByStatus.map(s => s.count);
+      expect(statusCounts.every(c => c === 6)).toBe(true);
+    });
+  });
+});

